export const CIRCUIT_BREAKER_V2_DATA: CircuitBreakerV2Entry[] = [
  ...BASE_CIRCUIT_BREAKER_V2_DATA,
  ...CIRCUIT_BREAKER_V2_ABB_ENTRIES.map((entry, index) => ({
    sNo: BASE_CIRCUIT_BREAKER_V2_DATA.length + index + 1,
    ...entry,
  })),
];

/* ---------- Helper: extract unique sorted values for a given field ---------- */
const cleanOptionValues = (values: string[]): string[] =>
  Array.from(new Set(values.map((v) => String(v).trim()).filter((v) => v.length > 0))).sort();

const uniqueSorted = (field: keyof CircuitBreakerV2Entry): string[] =>
  cleanOptionValues(CIRCUIT_BREAKER_V2_DATA.map((d) => String(d[field])));

type ParsedRatedCurrent =
  | { kind: "single"; valueA: number }
  | { kind: "range"; minA: number; maxA: number };

const parseRatedCurrentA = (raw: unknown): ParsedRatedCurrent | null => {
  const s = String(raw ?? "").trim();
  if (s.length === 0) return null;
  const normalized = s
    .replace(/\s+/g, "")
    // Support hyphen variants (en-dash/em-dash/minus) sometimes found in CSVs.
    .replace(/[–—−]/g, "-");

  const rangeMatch = normalized.match(/^(\d+(?:\.\d+)?)A?-(\d+(?:\.\d+)?)A?$/i);
  if (rangeMatch) {
    const a = Number(rangeMatch[1]);
    const b = Number(rangeMatch[2]);
    if (!Number.isFinite(a) || !Number.isFinite(b)) return null;
    const minA = Math.min(a, b);
    const maxA = Math.max(a, b);
    return { kind: "range", minA, maxA };
  }

  const singleMatch = normalized.match(/^(\d+(?:\.\d+)?)A?$/i);
  if (singleMatch) {
    const valueA = Number(singleMatch[1]);
    if (!Number.isFinite(valueA)) return null;
    return { kind: "single", valueA };
  }

  return null;
};

const guessRangeStepA = (minA: number, maxA: number): number => {
  const span = maxA - minA;
  if (!(span > 0)) return 1;
  if (span >= 100 && minA % 100 === 0 && maxA % 100 === 0) return 100;
  if (span >= 10 && minA % 10 === 0 && maxA % 10 === 0) return 10;
  return 1;
};

const buildRatedCurrentOptions = (entries: CircuitBreakerV2Entry[]): string[] => {
  const values = new Set<number>();

  for (const entry of entries) {
    const parsed = parseRatedCurrentA(entry.ratedCurrentA);
    if (!parsed) continue;

    if (parsed.kind === "single") {
      values.add(parsed.valueA);
      continue;
    }

    const step = guessRangeStepA(parsed.minA, parsed.maxA);
    for (let v = parsed.minA; v <= parsed.maxA; v += step) values.add(v);
    values.add(parsed.maxA);
  }

  return Array.from(values)
    .sort((a, b) => a - b)
    .map((a) => `${a}A`);
};

const parseVoltageValues = (raw: unknown): number[] => {
  const s = String(raw ?? "").trim();
  if (!s) return [];
  // Supports values like "440V", "440V,525V,690V", "230/400V", etc.
  const nums = s.match(/\d+(?:\.\d+)?/g) || [];
  const values = nums
    .map((x) => Number(x))
    .filter((n) => Number.isFinite(n));
  return Array.from(new Set(values));
};

const buildRatedVoltageOptions = (entries: CircuitBreakerV2Entry[]): string[] => {
  const values = new Set<number>();
  for (const entry of entries) {
    for (const v of parseVoltageValues(entry.ratedVoltage)) values.add(v);
  }

  return Array.from(values)
    .sort((a, b) => a - b)
    .map((v) => `${v}V`);
};

const normalizeBreakingCapacityKA = (raw: unknown): string => {
  const s = String(raw ?? "").trim();
  if (!s) return "";

  // Accept values like "42kA/1sec", "42kA", "42", etc.
  const m = s.match(/\d+(?:\.\d+)?/);
  if (!m) return s;

  const n = Number(m[0]);
  if (!Number.isFinite(n)) return s;
  return `${n}kA`;
};

const buildBreakingCapacityOptions = (entries: CircuitBreakerV2Entry[]): string[] => {
  const values = new Set<string>();
  for (const entry of entries) {
    const normalized = normalizeBreakingCapacityKA(entry.breakingCapacityKA);
    if (normalized) values.add(normalized);
  }

  return Array.from(values).sort((a, b) => {
    const na = Number(a.replace(/[^0-9.]/g, ""));
    const nb = Number(b.replace(/[^0-9.]/g, ""));
    if (Number.isFinite(na) && Number.isFinite(nb)) return na - nb;
    return a.localeCompare(b);
  });
};

export const cbV2RatedCurrentMatchesFilter = (entryRatedCurrentA: string, selectedRatedCurrentA: string): boolean => {
  const selected = parseRatedCurrentA(selectedRatedCurrentA);
  const entry = parseRatedCurrentA(entryRatedCurrentA);
  if (!selected || !entry) return false;

  // Keep old behavior for range selections (exact range match)
  if (selected.kind === "range") {
    return entry.kind === "range" && entry.minA === selected.minA && entry.maxA === selected.maxA;
  }

  // New behavior: single selection matches either single or containing range
  const a = selected.valueA;
  if (entry.kind === "single") return entry.valueA === a;
  return a >= entry.minA && a <= entry.maxA;
};

export const cbV2RatedVoltageMatchesFilter = (entryRatedVoltage: string, selectedRatedVoltage: string): boolean => {
  const selectedValues = parseVoltageValues(selectedRatedVoltage);
  const entryValues = parseVoltageValues(entryRatedVoltage);

  if (selectedValues.length > 0 && entryValues.length > 0) {
    // For single-value selections (from dropdown), match rows that contain that value.
    if (selectedValues.length === 1) return entryValues.includes(selectedValues[0]);

    // Keep deterministic behavior for multi-value selections by exact-set match.
    if (selectedValues.length !== entryValues.length) return false;
    const a = [...selectedValues].sort((x, y) => x - y);
    const b = [...entryValues].sort((x, y) => x - y);
    return a.every((v, i) => v === b[i]);
  }

  // Fallback to normalized string comparison when numeric parsing isn't possible.
  const norm = (x: string) => String(x || "").replace(/\s+/g, "").toLowerCase();
  return norm(entryRatedVoltage) === norm(selectedRatedVoltage);
};

export const cbV2BreakingCapacityMatchesFilter = (entryBreakingCapacityKA: string, selectedBreakingCapacityKA: string): boolean => {
  const entry = normalizeBreakingCapacityKA(entryBreakingCapacityKA);
  const selected = normalizeBreakingCapacityKA(selectedBreakingCapacityKA);
  if (!entry || !selected) return false;
  return entry === selected;
};

